100	// init from ram data.
101	// read config from param 'config', write net 'data' to memory.
102	int EEPTPU_SA::eeptpu_init(unsigned char* data, int datalen, unsigned char* config, int cfglen)
103	{
104	    int ret = -1;
105	
106	    /* Format:  for lib enc/pub
107	                interface(int*1), mem_base(int*1), tpureg_addr(int*1), reg_size(int*1, if not use, set 0),
108	                bin_type(int*1; enc=1; pub=2),
109	                mem_cnt(int*1), base_ofs0(int*1), ..., base_ofsN(int*1), mem_size(int*1), CntOut(int*1),
110	                DataOut0:  ofs(int*1), shape[0](int*1), shape[1](int*1), shape[2](int*1), shape[3](int*1), exp(int*1),
111	                DataOut1(if exist): ..... ,
112	                DataAlg_addr(int*1),
113	                DataIn:  ofs(int*1), shape[0](int*1), shape[1](int*1), shape[2](int*1), shape[3](int*1), exp(int*1),
114	                mean_count(int*1),mean_list(fp32*N),norm_list(fp32*N)
115	            */
116	    unsigned int* pcfg = (unsigned int*) config;
117	    if (cfglen < 8*4) return -1;
118	    //interface = *pcfg++;
119	    //mem_base = *pcfg++;
120	    //tpureg_addr = *pcfg++;
121	    //reg_size = *pcfg++;
122	    pcfg+=4;	// bare-metal mode, not use interface; set mem/reg base addr in src.
123	    mem_base = EEPTPU_MEM_BASE_ADDR;
124	    tpureg_addr = EEPTPU_REG_BASE_ADDR;
125	    reg_size = 0;	// ignore
126	
127	    bin_type = *pcfg++;
128	    mem_cnt = *pcfg++;
129	    if (bin_type == 1)
130	    {
131	        hwbase0 = (*pcfg++) + mem_base;
132	        hwbase1 = (*pcfg++) + mem_base;
133	    }
134	    else if (bin_type == 2)
135	    {
136	        hwbase0 = (*pcfg++) + mem_base;
137	        hwbase1 = (*pcfg++) + mem_base;
138	        hwbase2 = (*pcfg++) + mem_base;
139	        hwbase3 = (*pcfg++) + mem_base;
140	    }
141	
142	    memsize = *pcfg++;
143	    int cnt_out = *pcfg++;
144	    printf("output cnt = %d\n", cnt_out);
145	    //if (cfglen < ( 8*4 + cnt_out*6*4 + 1*4 ) ) return -1;
