309	int epmat_get_size(int c, int h, int w)
310	{
311	    if (h == 1 && w == 1) return round_up(c, 16) * 2;
312	    else return (h * w * round_up(c, 16)  * 2);
313	}
314	ncnn::Mat epmat2nmat_simple(int channel, int height, int width, unsigned char* epmat, int exp)
315	{
316	    ncnn::Mat dstmat = ncnn::Mat(width);
317	    float* pdst = (float*)dstmat;
318	    int div_val = pow(2, exp);
319	    unsigned char* p_epmat = epmat;
320	    for (int w=0; w < channel * height * width; w++)
321	    {
322	        short tmpval = *p_epmat++;
323	        tmpval |= (*p_epmat) << 8;
324	        p_epmat++;
325	        *(pdst + w) = (float)tmpval / div_val;
326	    }
327	
328	    return dstmat;
329	}
330	ncnn::Mat epmat2nmat(int channel, int height, int width, unsigned char *epmat, int exp)
331	{
332	    if (epmat == NULL) return ncnn::Mat();
333	    if (height == 1 && channel == 1)
334	    {
335	        return epmat2nmat_simple(channel, height, width, epmat, exp);
336	    }
337	
338	    ncnn::Mat dstmat = ncnn::Mat(width, height, channel);
339	
340	    int ch_group = channel / 16;
341	    if (channel % 16) ch_group++;
342	    int epmat_ch_group = height * width * 16;
343	    int div_val = pow(2, exp);
344	
345	    for (int c=0; c < channel; c++)
346	    {
347	        int curr_ch_group = c / 16;
348	        float* pdst = (float*)dstmat.channel(c).data;
349	        int epmat_offset = (curr_ch_group * epmat_ch_group + (c % 16)) * 2;
350	
351	        for (int hw=0; hw < height * width; hw++)
352	        {
353	            short tmpval =    *(epmat + epmat_offset + 0);
354	            tmpval |= ((*(epmat + epmat_offset + 1)) << 8);
355	            *pdst++ = (float)tmpval / div_val;
356	            epmat_offset += 32;
357	        }
358	    }
359	
360	    return dstmat;
361	}
